#include<iostream>#include<vector>#include<algorithm>using namespace std;int main(){    ios_base::sync_with_stdio(false);    cin.tie(NULL);          int n,q;        cin>>n>>q;        vector<int>pos(51,-1);        for(int i=1;i<=n;i++){            int color;            cin>>color;            if(pos[color]==-1){                pos[color]=i;            }        }                while(q--){            int t;            cin>>t;            int current_pos= pos[t];            cout<<current_pos<<" ";            for(int i=1;i<=50;i++){                if(pos[i]!=-1 && pos[i]<current_pos){                    pos[i]++;                }            }            pos[t] = 1;        }    }